import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

type Orientation = "horizontal" | "vertical"

interface StepperContextValue {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: Orientation
}

const StepperContext = React.createContext<StepperContextValue>({
  activeStep: 0,
  setActiveStep: () => {},
  orientation: "horizontal",
})

function useStepper() {
  return React.useContext(StepperContext)
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue>({
  step: 0,
  isActive: false,
  isCompleted: false,
})

function useStepperItem() {
  return React.useContext(StepperItemContext)
}

interface StepperProps extends React.ComponentProps<"div"> {
  activeStep?: number
  defaultStep?: number
  onStepChange?: (step: number) => void
  orientation?: Orientation
}

function Stepper({
  activeStep: activeStepProp,
  defaultStep = 0,
  onStepChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [activeStepState, setActiveStepState] = React.useState(defaultStep)
  const isControlled = activeStepProp !== undefined
  const activeStep = isControlled ? activeStepProp : activeStepState

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (!isControlled) {
        setActiveStepState(step)
      }
      onStepChange?.(step)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider value={{ activeStep, setActiveStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("cn-stepper", className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

function StepperList({ className, ...props }: React.ComponentProps<"ol">) {
  const { orientation } = useStepper()
  return (
    <ol
      data-slot="stepper-list"
      data-orientation={orientation}
      className={cn("cn-stepper-list flex", className)}
      {...props}
    />
  )
}

interface StepperItemProps extends React.ComponentProps<"li"> {
  step: number
}

function StepperItem({ step, className, ...props }: StepperItemProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step
  const isCompleted = activeStep > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <li
        data-slot="stepper-item"
        data-state={
          isActive ? "active" : isCompleted ? "completed" : "inactive"
        }
        className={cn("cn-stepper-item", className)}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { step } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      onClick={() => setActiveStep(step)}
      className={cn("cn-stepper-trigger", className)}
      {...props}
    />
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("cn-stepper-title", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("cn-stepper-description", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden="true"
      className={cn("cn-stepper-separator", className)}
      {...props}
    />
  )
}

function StepperContent({ className, ...props }: React.ComponentProps<"div">) {
  const { isActive } = useStepperItem()

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("cn-stepper-content", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

