  const { isActive } = useStepperItem()

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

