"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    label: "Account",
    description: "Create your account",
    content: "Enter your email address and choose a secure password.",
  },
  {
    label: "Profile",
    description: "Set up your profile",
    content: "Tell us your name and upload a profile photo.",
  },
  {
    label: "Review",
    description: "Review and submit",
    content: "Check your details and complete your registration.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="w-full max-w-md space-y-6">
      <Stepper activeStep={activeStep} onStepChange={setActiveStep}>
        <StepperList>
          {steps.map((step, index) => (
            <React.Fragment key={step.label}>
              <StepperItem step={index}>
                <StepperTrigger>
                  <div className="flex flex-col items-start">
                    <StepperTitle>{step.label}</StepperTitle>
                    <StepperDescription>{step.description}</StepperDescription>
                  </div>
                </StepperTrigger>
                {index < steps.length - 1 && <StepperSeparator />}
              </StepperItem>
            </React.Fragment>
          ))}
        </StepperList>

        {steps.map((step, index) => (
          <StepperItem key={step.label} step={index}>
            <StepperContent className="rounded-lg border p-4">
              {step.content}
            </StepperContent>
          </StepperItem>
        ))}
      </Stepper>

      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(0, s - 1))}
          disabled={activeStep === 0}
        >
          Back
        </Button>
        <Button
          onClick={() =>
            setActiveStep((s) => Math.min(steps.length - 1, s + 1))
          }
          disabled={activeStep === steps.length - 1}
        >
          {activeStep === steps.length - 2 ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}

